import { nodeApi, dotnetCustomerApi } from '../axios';
import { ENDPOINTS } from '../config';

const authService = {
  login: (data) => nodeApi.post(ENDPOINTS.LOGIN, data),
  register: (data) => nodeApi.post(ENDPOINTS.REGISTER, data),
  loginGoogle: (data) => nodeApi.post(ENDPOINTS.LOGIN_GOOGLE, data),
  forgotPassword: (data) => nodeApi.post(ENDPOINTS.FORGOT_PASSWORD, data),
  verifyOtp: (data) => nodeApi.post(ENDPOINTS.VERIFY_OTP, data),
  resetPassword: (data) => nodeApi.post(ENDPOINTS.RESET_PASSWORD, data),
  changePassword: (data) => nodeApi.post(ENDPOINTS.CHANGE_PASSWORD, data),
  logout: () => nodeApi.post(ENDPOINTS.LOGOUT),
  getProfile: () => nodeApi.get(ENDPOINTS.GET_PROFILE),
  saveProfile: (data) => nodeApi.post(ENDPOINTS.SAVE_PROFILE, data),
  uploadProfilePic: (formData) => nodeApi.post(ENDPOINTS.UPLOAD_PROFILE_PIC, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  uploadBanner: (formData) => nodeApi.post(ENDPOINTS.UPLOAD_BANNER, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  updateVideo: (formData) => nodeApi.post(ENDPOINTS.UPDATE_VIDEO, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  updateWallpaper: (data) => nodeApi.post(ENDPOINTS.UPDATE_WALLPAPER, data),
  updateUserType: (data) => dotnetCustomerApi.post(ENDPOINTS.UPDATE_USER_TYPE, data),
  getOnlineStatus: (params) => dotnetCustomerApi.get(ENDPOINTS.GET_ONLINE_STATUS, { params }),
  setOnlineStatus: (data) => dotnetCustomerApi.post(ENDPOINTS.SET_ONLINE_STATUS, data),
};

export default authService;
